        import sailpoint.api.TaskManager;
        import sailpoint.object.Attributes;
        import sailpoint.object.TaskDefinition;

        TaskManager tm = new TaskManager(context);
        TaskDefinition taskDefObj = context.getObject(TaskDefinition.class, "Ascension or AMITA User Bulk Load Report");
        if(taskDefObj != null){
        Attributes arguments = taskDefObj.getArguments();
        arguments.put("notes", notes);
        arguments.put("launcher", launcher);
        tm.run(taskDefObj, arguments);
        }
